dashboard.definition:
{
  "title": "Source - Perfmon",
  "description": "Windows Performance Monitor — prevent outages through early detection of CPU, memory, and disk exhaustion",
  "dataSources": {
    "ds_total_events": {
      "type": "ds.search",
      "name": "Total Perfmon Events Over Time",
      "options": {
        "query": "| tstats count where index=fake_tshrt sourcetype=\"FAKE:Perfmon:*\" by _time span=1h"
      }
    },
    "ds_hosts_reporting": {
      "type": "ds.search",
      "name": "Servers Monitored",
      "options": {
        "query": "| tstats dc(host) as count where index=fake_tshrt sourcetype=\"FAKE:Perfmon:*\""
      }
    },
    "ds_peak_cpu": {
      "type": "ds.search",
      "name": "Peak CPU %",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:Perfmon:Processor\" counter=\"% Processor Time\" instance=\"_Total\" | stats max(Value) as count | eval count=round(count,1).\"%\""
      }
    },
    "ds_critical_disk": {
      "type": "ds.search",
      "name": "Critical Disk (>90%)",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:Perfmon:LogicalDisk\" counter=\"% Free Space\" | stats latest(Value) as free_pct by host, instance | where free_pct<10 | stats count"
      }
    },
    "ds_cpu_over_time": {
      "type": "ds.search",
      "name": "CPU Usage Over Time by Host",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:Perfmon:Processor\" counter=\"% Processor Time\" instance=\"_Total\" | timechart span=1h avg(Value) by host"
      }
    },
    "ds_memory_over_time": {
      "type": "ds.search",
      "name": "Memory Usage Over Time by Host",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:Perfmon:Memory\" counter=\"% Committed Bytes In Use\" | timechart span=1h avg(Value) by host"
      }
    },
    "ds_current_resources": {
      "type": "ds.search",
      "name": "Current Resource Usage by Server",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:Perfmon:Processor\" counter=\"% Processor Time\" instance=\"_Total\" | stats latest(Value) as cpu_pct by host | eval cpu_pct=round(cpu_pct,1) | sort -cpu_pct | rename host as \"Server\" cpu_pct as \"CPU %\""
      }
    },
    "ds_high_alerts": {
      "type": "ds.search",
      "name": "Recent High-Value Alerts",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:Perfmon:*\" Value>90 (counter=\"% Processor Time\" OR counter=\"% Committed Bytes In Use\") | table _time host counter instance Value | sort -_time | head 30 | rename host as \"Host\" counter as \"Counter\" instance as \"Instance\" Value as \"Value %\""
      }
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Source — Perfmon\n\n**Sourcetypes:** `FAKE:Perfmon:Processor`, `FAKE:Perfmon:Memory`, `FAKE:Perfmon:LogicalDisk`, `FAKE:Perfmon:Network_Interface` | **Coverage:** Windows server performance metrics | **Format:** Key-value pairs\n\n**Why monitor?** Prevent outages through early detection of CPU spikes, memory exhaustion, and disk space depletion before they impact business operations.",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_kpi_total_events": {
      "type": "splunk.singlevalue",
      "title": "Total Metrics",
      "dataSources": { "primary": "ds_total_events" },
      "options": {
        "majorValue": "> sparklineValues | lastPoint()",
        "sparklineValues": "> primary | seriesByName('count')",
        "sparklineDisplay": "below",
        "majorColor": "#00D2FF",
        "backgroundColor": "transparent",
        "showSparklineAreaGraph": true,
        "sparklineStrokeColor": "#00D2FF"
      }
    },
    "viz_kpi_hosts": {
      "type": "splunk.singlevalue",
      "title": "Servers Monitored",
      "dataSources": { "primary": "ds_hosts_reporting" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#7B56DB",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_peak_cpu": {
      "type": "splunk.singlevalue",
      "title": "Peak CPU %",
      "dataSources": { "primary": "ds_peak_cpu" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#F8BE34",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_critical_disk": {
      "type": "splunk.singlevalue",
      "title": "Critical Disk (>90%)",
      "dataSources": { "primary": "ds_critical_disk" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#DC4E41",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_cpu_over_time": {
      "type": "splunk.line",
      "title": "CPU Usage Over Time by Host",
      "dataSources": { "primary": "ds_cpu_over_time" },
      "options": {
        "legendDisplay": "right",
        "nullValueDisplay": "zero",
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "% Processor Time",
        "yAxisTitleVisibility": "show",
        "seriesColors": ["#00D2FF", "#7B56DB", "#53A051", "#F8BE34", "#DC4E41", "#009CEB", "#F1813F", "#00CDAF"]
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_memory_over_time": {
      "type": "splunk.line",
      "title": "Memory Usage Over Time by Host",
      "dataSources": { "primary": "ds_memory_over_time" },
      "options": {
        "legendDisplay": "right",
        "nullValueDisplay": "zero",
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "% Committed Bytes In Use",
        "yAxisTitleVisibility": "show",
        "seriesColors": ["#00D2FF", "#7B56DB", "#53A051", "#F8BE34", "#DC4E41", "#009CEB", "#F1813F", "#00CDAF"]
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_current_resources": {
      "type": "splunk.bar",
      "title": "Current CPU Usage by Server",
      "dataSources": { "primary": "ds_current_resources" },
      "options": {
        "seriesColors": ["#F8BE34"],
        "legendDisplay": "off",
        "xAxisTitleText": "CPU %",
        "xAxisTitleVisibility": "show",
        "yAxisTitleVisibility": "hide",
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_alerts_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "### Recent High-Value Alerts (Value > 90%)",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_high_alerts": {
      "type": "splunk.table",
      "title": "Recent High-Value Alerts",
      "dataSources": { "primary": "ds_high_alerts" },
      "options": {
        "count": 20,
        "showRowNumbers": false
      },
      "showProgressBar": true,
      "showLastUpdated": true
    }
  },
  "inputs": {
    "input_global_trp": {
      "type": "input.timerange",
      "title": "Time Range",
      "options": {
        "token": "global_time",
        "defaultValue": "1767225600,1769904000"
      }
    }
  },
  "defaults": {
    "dataSources": {
      "ds.search": {
        "options": {
          "queryParameters": {
            "earliest": "$global_time.earliest$",
            "latest": "$global_time.latest$"
          }
        }
      }
    }
  },
  "layout": {
    "type": "grid",
    "globalInputs": ["input_global_trp"],
    "structure": [
      { "item": "viz_header", "type": "block", "position": { "x": 0, "y": 0, "w": 1200, "h": 150 } },
      { "item": "viz_kpi_total_events", "type": "block", "position": { "x": 0, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_hosts", "type": "block", "position": { "x": 300, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_peak_cpu", "type": "block", "position": { "x": 600, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_critical_disk", "type": "block", "position": { "x": 900, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_cpu_over_time", "type": "block", "position": { "x": 0, "y": 270, "w": 600, "h": 350 } },
      { "item": "viz_memory_over_time", "type": "block", "position": { "x": 600, "y": 270, "w": 600, "h": 350 } },
      { "item": "viz_current_resources", "type": "block", "position": { "x": 0, "y": 620, "w": 1200, "h": 300 } },
      { "item": "viz_alerts_header", "type": "block", "position": { "x": 0, "y": 920, "w": 1200, "h": 50 } },
      { "item": "viz_high_alerts", "type": "block", "position": { "x": 0, "y": 970, "w": 1200, "h": 400 } }
    ]
  }
}
